from flask import Blueprint, jsonify, render_template
from datetime import datetime

diagnostics_bp = Blueprint("diagnostics", __name__)


@diagnostics_bp.route("/jarvis/diagnostics")
def diagnostics():
    return render_template("templates/jarvis/diagnostics.html",
                           title="Diagnostics",
                           data={"status": "online", "page": "diagnostics", "timestamp": datetime.utcnow().isoformat() + "Z"})
